+func attentionBoolDetail(details map[string]any, key string) bool {
+	if details == nil {
+		return false
+	}
+	value, ok := details[key]
+	if !ok {
+		return false
+	}
+	switch v := value.(type) {
+	case bool:
+		return v
+	case string:
+		normalized := strings.TrimSpace(strings.ToLower(v))
+		return normalized == "true" || normalized == "1" || normalized == "yes"
+	case int:
+		return v != 0
+	case int32:
+		return v != 0
+	case int64:
+		return v != 0
+	case float64:
+		return v != 0
+	}
+	return false
+}
